          {/* Success badge */}
          <div style={{width:64,height:64,borderRadius:"50%",background:"linear-gradient(135deg,"+C.greenLight+",#A7F3D0)",border:"3px solid "+C.green,display:"flex",alignItems:"center",justifyContent:"center",margin:"0 auto 18px",fontSize:28,animation:"glow 2s ease-in-out infinite"}}>✓</div>
